import os
import re
import sys
import getpass
from pathlib import Path

try:
    import mysql.connector
except ImportError as e:
    raise SystemExit("mysql-connector-python is required. Install with: pip install mysql-connector-python") from e


def enable_local_infile_mysql_config():
    possible_paths = [
        "/etc/my.cnf",
        "/etc/mysql/my.cnf",
        "/etc/mysql/mysql.conf.d/mysqld.cnf",
        os.path.expanduser("~/.my.cnf"),
    ]
    for path in possible_paths:
        p = Path(path)
        if not p.exists() or not p.is_file():
            continue
        try:
            content = p.read_text(encoding="utf-8")
        except Exception:
            continue
        if "local_infile" in content:
            return
        try:
            with p.open("a", encoding="utf-8") as f:
                f.write("\n[mysqld]\nlocal_infile=1\n")
            return
        except Exception:
            continue


def validate_identifier(name):
    if not re.fullmatch(r"[A-Za-z0-9_]+", name or ""):
        raise ValueError(f"Invalid MySQL identifier: {name!r}")
    return name


def prompt(msg, default=None):
    value = input(f"{msg}{' [' + default + ']' if default else ''}: ").strip()
    return value or default


def get_connection():
    host = prompt("MySQL host", "127.0.0.1")
    port = int(prompt("MySQL port", "3306"))
    user = prompt("MySQL user")
    password = getpass.getpass("MySQL password: ")
    database = prompt("MySQL database")
    conn = mysql.connector.connect(
        host=host,
        port=port,
        user=user,
        password=password,
        database=database,
        allow_local_infile=True,
        use_pure=True,
    )
    return conn


def load_file(cursor, file_path, table_name, columns=None, field_terminated_by=",", enclosed_by='"', escaped_by="\\", lines_terminated_by="\n", ignore_lines=1):
    file_path = str(Path(file_path).expanduser().resolve())
    if not Path(file_path).exists():
        raise FileNotFoundError(file_path)

    table_name = validate_identifier(table_name)

    cols_sql = ""
    if columns:
        cols_sql = "({})".format(", ".join(validate_identifier(c) for c in columns))

    enclosed_sql = f" ENCLOSED BY '{enclosed_by}'" if enclosed_by is not None else ""
    escaped_sql = f" ESCAPED BY '{escaped_by}'" if escaped_by is not None else ""

    sql = (
        "LOAD DATA LOCAL INFILE '{} ' INTO TABLE {} "
        "FIELDS TERMINATED BY '{}'{}{} "
        "LINES TERMINATED BY '{}' "
        "IGNORE {} LINES {}"
    ).format(
        file_path,
        table_name,
        field_terminated_by,
        enclosed_sql,
        escaped_sql,
        lines_terminated_by,
        int(ignore_lines),
        cols_sql,
    )

    sql = sql.replace("'{0} '", "'{0}'") if False else sql
    sql = sql.replace(file_path + " ", file_path)

    cursor.execute(sql)


def main():
    enable_local_infile_mysql_config()

    conn = None
    try:
        conn = get_connection()
        cursor = conn.cursor()

        table_name = prompt("Target table name")
        cols_input = prompt("Comma-separated column names (optional)", "")
        columns = [c.strip() for c in cols_input.split(",") if c.strip()] if cols_input else None

        while True:
            file_path = prompt("CSV file path (blank to finish)")
            if not file_path:
                break
            try:
                load_file(cursor, file_path, table_name, columns=columns)
                conn.commit()
                print(f"Imported: {file_path}")
            except Exception as e:
                conn.rollback()
                print(f"Failed: {file_path} -> {e}", file=sys.stderr)

    finally:
        if conn is not None and conn.is_connected():
            conn.close()


if __name__ == "__main__":
    main()